// Merge trigger sources — schedule uses defaults, webhook uses body
const item = $input.first();
const body = item.json.body || item.json;

return [{
  json: {
    client_id:   body.client_id   || null,
    workspace_id: body.workspace_id || null,
    user_id:     body.user_id     || process.env.DEFAULT_USER_ID || '',
    target_urls: body.target_urls || [
      // Default prospect list URLs — edit in Supabase or pass via webhook
      // e.g. LinkedIn Sales Nav exports, Apollo.io CSV exports, etc.
    ],
    max_leads:   body.max_leads  || 50,
    run_id:      crypto.randomUUID(),
    triggered_at: new Date().toISOString(),
  }
}];

// ─────────────────────────────────────────────────────────
// BISHOP SCRAPER — extracts lead data from target URLs
// ─────────────────────────────────────────────────────────
// In production, replace this with:
//   - Clay.ai API call
//   - Apollo.io API call  
//   - Hunter.io API call
//   - Custom Puppeteer/Playwright scraper
//
// This node returns a MOCK list so you can test the full pipeline.
// Replace $scraped with your actual scraped data.

const config = $input.first().json;
const targetUrls = config.target_urls || [];

// MOCK DATA — replace with real scraper calls
const mockLeads = [
  {
    name: 'Sarah Chen',
    email: 'sarah.chen@acmecorp.io',
    company: 'Acme Corp',
    title: 'Head of Operations',
    phone: null,
    linkedin_url: 'https://linkedin.com/in/sarah-chen-ops',
    source_url: targetUrls[0] || 'scrape',
    context_notes: 'Growing SaaS company, recently hired 3 ops staff. Pain: manual lead routing.',
    enrichment_data: {
      company_size: '50-200',
      funding_stage: 'Series A',
      tech_stack: ['Salesforce', 'Slack', 'Notion']
    }
  },
  {
    name: 'Marcus Webb',
    email: 'm.webb@brightpaths.com',
    company: 'BrightPaths',
    title: 'CEO',
    phone: '+14155550123',
    linkedin_url: 'https://linkedin.com/in/marcuswebb',
    source_url: targetUrls[0] || 'scrape',
    context_notes: 'B2B SaaS, 12-person team. No dedicated SDR. Looking to scale outbound.',
    enrichment_data: {
      company_size: '10-50',
      funding_stage: 'Bootstrapped',
      annual_revenue: '2M'
    }
  }
];

// Attach run config to each lead
return mockLeads.map(lead => ({
  json: {
    ...lead,
    client_id:    config.client_id,
    workspace_id: config.workspace_id,
    user_id:      config.user_id,
    run_id:       config.run_id,
  }
}));

// Batch all scraped leads into one array for pawn-verify
const items = $input.all();
if (!items.length) return [];

// Take config from first item
const first = items[0].json;

return [{
  json: {
    client_id:    first.client_id,
    workspace_id: first.workspace_id,
    user_id:      first.user_id,
    run_id:       first.run_id,
    leads: items.map(i => i.json),
  }
}];

// Log Pawn stats and extract clean leads for Bishop
const result = $input.first().json;
const stats = result.stats || {};

console.log(`[Pawn] Total: ${stats.total} | Clean: ${stats.clean} | Dupes: ${stats.duplicates} | Invalid: ${stats.invalid}`);

if (!result.clean || result.clean.length === 0) {
  console.log('[Pawn] No clean leads — stopping run.');
  return [];
}

// Return each clean lead as separate item for Bishop processing
return result.clean.map(lead => ({ json: lead }));

// After sweep, auto-send approved drafts
// In PILOT mode: drafts go to Supabase for human review
// In AUTO mode: call bishop-send for each draft

const sweepResult = $input.first().json;
const AUTO_SEND = process.env.BISHOP_AUTO_SEND === 'true';

if (AUTO_SEND) {
  console.log('[Bishop] AUTO_SEND enabled — drafts will be sent automatically');
} else {
  console.log('[Bishop] PILOT mode — drafts saved for human review in Supabase');
}

return [{ json: { ...sweepResult, auto_send: AUTO_SEND } }];

// Build a summary report for Queen / Slack notification
const items = $input.all();
const sendResults = items.map(i => i.json).filter(r => r.success);

const summary = {
  timestamp: new Date().toISOString(),
  sent_count: sendResults.length,
  failed_count: items.length - sendResults.length,
  leads_contacted: sendResults.map(r => r.to),
};

console.log('[Bishop] Run complete:', summary);
return [{ json: summary }];
